impl Lexer for SwiftLexer {
    fn get_tokens(&self, code: &str) -> Vec<(TokenType, String)> {
        let table = TABLE.get_or_init(build_table);
        let mut tokens = tokenize(table, code);
        let remap_0 = REMAP_WORDS_0.get_or_init(build_remap_0);
        for (t, v) in &mut tokens {
            if (*t == NAME || *t == NAME_CLASS) && remap_0.contains(v.as_str()) {
                *t = NAME_BUILTIN_PSEUDO;
            }
        }
        tokens
    }
}
